gold_sql:
SELECT EXISTS (
    SELECT 1
    FROM npcyf_schema."CROP"
    WHERE crop_name ILIKE '%wheat%'
) AS is_wheat_available;

model_sql:
SELECT crop_name
FROM npcyf_schema."CROP"
WHERE crop_name = 'WHEAT';

gold_sql:
SELECT DISTINCT season_name
FROM npcyf_schema."SEASON"
ORDER BY season_name;

model_sql:
SELECT rainfall_data_collection_id, SUM(rainfall_value) AS total_rainfall
FROM npcyf_schema."LOCATION_RAINFALL"
GROUP BY rainfall_data_collection_id;

SELECT crop_id
FROM npcyf_schema."CROP"
WHERE crop_name = 'Rice';
